            { type: "video", title: "The Truth About Fat (2020) | Full Documentary | NOVA (53 minutes)", provider: "📚 School\u0027s Library · youtube.com", url: "https://www.youtube.com/watch?v=Ubn8EHRBZJI", note: "From the Wolves classroom library." }
