            { type: "book", title: "Cambridge Lower Secondary Science Learner's Book 8", author: "Cambridge University Press (2nd ed.)", chapter: "Unit: Forces and energy (Stage 8)", note: "Motion, speed, forces, mass vs weight, pressure and energy are covered in the Stage 8 'Forces and energy' unit (and extended in Stage 9).", url: "https://www.cambridge.org/us/education/subject/science/cambridge-primary-and-lower-secondary-science-2nd-edition/cambridge-lower-secondary-science-2nd-edition-digital-learners-book-8-1-year-learners-book-8-digital-access-1-year?isbn=9781108742825" }
